const __m128i space = _mm_set1_epi8(' ');
const __m128i tab = _mm_set1_epi8('\t');
const __m128i newline = _mm_set1_epi8('\n');
const __m128i cr = _mm_set1_epi8('\r');
while (ptr < end) {
  __m128i data = _mm_loadu_si128((__m128i*)ptr);
  __m128i is_space = _mm_cmpeq_epi8(data, space);
  __m128i is_tab = _mm_cmpeq_epi8(data, tab);
  __m128i is_nl = _mm_cmpeq_epi8(data, newline);
  __m128i is_cr = _mm_cmpeq_epi8(data, cr);
  __m128i is_ws = _mm_or_si128(_mm_or_si128(is_space, is_tab), _mm_or_si128(is_nl, is_cr));
  int mask = _mm_movemask_epi8(is_ws);
  if (mask != 0xFFFF) break;
  ptr += 16;
}

const __m128i data = _mm_loadu_si128((__m128i*)ptr);
const __m128i zero = _mm_set1_epi8('0');
const __m128i nine = _mm_set1_epi8('9');
const __m128i ge_zero = _mm_cmpgt_epi8(data, _mm_sub_epi8(zero, _mm_set1_epi8(1)));
const __m128i le_nine = _mm_cmpgt_epi8(_mm_add_epi8(nine, _mm_set1_epi8(1)), data);
const __m128i is_digit = _mm_and_si128(ge_zero, le_nine);
int mask = _mm_movemask_epi8(is_digit);

#include <cpuid.h>

bool has_sse42(void) {
  unsigned int eax, ebx, ecx, edx;
  if (!__get_cpuid(1, &eax, &ebx, &ecx, &edx)) return false;
  return (ecx & bit_SSE4_2) != 0;
}

bool has_avx2(void) {
  unsigned int eax, ebx, ecx, edx;
  if (!__get_cpuid(7, &eax, &ebx, &ecx, &edx)) return false;
  return (ebx & bit_AVX2) != 0;
}

#include <sys/auxv.h>
#include <asm/hwcap.h>

bool has_neon(void) {
#ifdef __aarch64__
  return true; // All ARM64 has NEON
#else
  return (getauxval(AT_HWCAP) & HWCAP_NEON) != 0;
#endif
}

bool has_sve(void) {
#ifdef __aarch64__
  return (getauxval(AT_HWCAP) & HWCAP_SVE) != 0;
#else
  return false;
#endif
}

typedef int (*parse_func_t)(const char* json);

static parse_func_t select_parser(void) {
  static parse_func_t cached = NULL;
  if (cached) return cached;

  if (has_avx2()) {
    cached = parse_json_avx2;
  } else if (has_sse42()) {
    cached = parse_json_sse42;
  } else {
    cached = parse_json_scalar;
  }
  return cached;
}

int parse_json(const char* json) {
  static parse_func_t parser = NULL;
  if (!parser) parser = select_parser();
  return parser(json);
}
